class Solution {
    public int longestDecomposition(String text) {
        int n = text.length();
        int ans = 0;
        for (int i = n / 2; i >= 1; i--) {
            if (n % i == 0) {
                boolean flag = true;
                for (int j = 0; j < i; j++) {
                    if (!text.substring(j, j + i).equals(text.substring(n - i + j, n - j))) {
                        flag = false;
                        break;
                    }
                }
                if (flag) {
                    ans = i;
                    break;
                }
            }
        }
        return ans;
    }
}
